      "prompt": "像素风产品规格海报，16:9 横版——米色做旧纸张底；一台[硬件物件]用清晰像素风绘制，3/4 视角悬浮，底下一块硬边纯黑扁平投影，每颗按钮、旋钮、接口都锁在像素格线上；机身配色白底+红+蓝+柠檬绿+橙；顶部通栏红色像素体两词英文大标“[标题]”，物件顶部穿破标题字母；左栏是栏目标签“[栏目/编号]”+条形码+短正文+规格表“[规格内容]”（数值要像真实产品参数）；右侧一列竖排小规格框“[机型代码/类型/版本]”；角落放期号和档案编号；可选第二行像素大字标语“[标语]”；画面所有文字均为英文——不要写实渲染、不要平滑抗锯齿曲线、不要渐变柔和阴影、不要融化错位的按键、不要超过 5 种点缀色\n\n--- JSON version ---\n{\n  \"style_rules\": {\n    \"background\": \"aged cream paper with subtle grain\",\n    \"hero_object\": \"one hardware device in crisp pixel art, 3/4 isometric-ish view, floating with a hard-edged solid black flat shadow beneath — every button, knob and port snapped to the pixel grid\",\n    \"object_palette\": \"white/cream body + red + blue + lime green + orange accents + black details, consistent across the series\",\n    \"title\": \"giant red pixel/blocky 2-word title spanning full width at top; the object overlaps and breaks into the letters\",\n    \"left_column\": \"category label (POCKET OPTIC / FIELD TEST 04 format) + barcode + short body copy + feature bullets or spec table with realistic product-grade values\",\n    \"right_sidebar\": \"vertical stack of small spec boxes (unit code / type / mode / rev)\",\n    \"corner_index\": \"issue/index numbers + archive code in corners\",\n    \"secondary_slogan\": \"optional second pixel-font phrase (MAKE NOISE / GRID ONE style)\",\n    \"typography\": \"mono/pixel fonts only, red + black text\",\n    \"format\": \"16:9 horizontal\"\n  },\n  \"negative\": \"photorealistic rendering, smooth anti-aliased curves, gradient or soft shadows, melted/misaligned buttons, cluttered background, more than 5 accent colors\",\n  \"variables\": {\n    \"hardware_object\": \"[instant camera / FPV drone / sampler-drum machine / modular toolbox]\",\n    \"title\": \"[2-word title: SNAP FAST / LIFT MODE / BEAT LOAD / BUILD NOW]\",\n    \"category_label\": \"[POCKET OPTIC FIELD TEST 04 / FLIGHT UNIT TEST GRID / SAMPLE DECK RHYTHM UNIT / UTILITY KIT MODULE INDEX]\",\n    \"spec_content\": \"[realistic values: TRACK COUNT 16, SWING 54% / CLASS A1, UNIT 007 / MODE AUTO, FLASH QUICK]\",\n    \"sidebar_fields\": \"[unit code / type / mode / rev stack]\",\n    \"secondary_slogan\": \"[MAKE NOISE / GRID ONE / optional]\"\n  }\n}",
